import { formatCSV } from './format-csv.js';
import { downloadCSV } from '../../../../core/utils/download.js';
import { CSS_DOWNLOAD_FILENAME } from '../../../core/constants.js';
import { TimeseriesRawDataPerVariant } from '../../context/TimeseriesRawData.context.js';

/**
 * Builds CSV from Timeseries format-csv
 *
 * @param series - Timeseries series
 */
export const buildAndDownloadCsv = (series: TimeseriesRawDataPerVariant) => {
  const csvString = formatCSV(series);
  downloadCSV(csvString, CSS_DOWNLOAD_FILENAME);
};
